  spend(
    _datum: Option<Void>,
    redeemer: ConfigRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(config_input) =
      transaction.find_input(self.reference_inputs, redeemer.config_ref)
    expect InlineDatum(raw) = config_input.output.datum
    expect cfg: Config = raw
    let total_out =
      list.foldl(
        self.outputs,
        0,
        fn(o, acc) {
          if o.address.payment_credential == cfg.admin {
            acc + assets.lovelace_of(o.value)
          } else {
            acc
          }
        },
      )
    total_out >= cfg.min_ada
  }
}

