    self: Transaction,
  ) -> Bool {
    expect Some(cfg_input) =
      transaction.find_input(self.reference_inputs, redeemer.config_ref)
    expect InlineDatum(raw) = cfg_input.output.datum
    expect cfg: FeeConfig = raw
    let fee_bps =
      if redeemer.amount <= cfg.low_threshold {
        cfg.low_fee_bps
      } else {
        cfg.high_fee_bps
      }
    let fee_due = redeemer.amount * fee_bps / 10000
    list.any(
      self.outputs,
      fn(o) {
        o.address.payment_credential == cfg.fee_address
          && assets.lovelace_of(o.value) >= fee_due
      },
    )
  }
}

