pub type ClaimRedeemer {
  config_ref: OutputReference,
  claim_time: Int,
  recipient: ByteArray,
}

validator staking_reward_spend {
  spend(
    datum: Option<StakingDatum>,
    redeemer: ClaimRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(stake_datum) = datum
    expect Some(cfg_input) =
      transaction.find_input(self.reference_inputs, redeemer.config_ref)
    expect InlineDatum(raw) = cfg_input.output.datum
    expect cfg: StakingConfig = raw
    let elapsed = redeemer.claim_time - stake_datum.deposit_time
    let epochs = elapsed / cfg.epoch_length
    let reward = stake_datum.deposited * cfg.reward_rate_bps * epochs / 10000
    let total_due = stake_datum.deposited + reward
    list.any(
      self.outputs,
      fn(o) {
        o.address.payment_credential == redeemer.recipient
          && assets.lovelace_of(o.value) >= total_due
      },
    )
