pub type ConstitutionConfig {
  min_term_length: Int,
  max_term_length: Int,
  current_term_length: Int,
}

fn validate_term_length_in_proposal(
  proposed_params: ProtocolParameters,
  config: ConstitutionConfig,
) -> Bool {
  when proposed_params.committee_max_term_length is {
    Some(new_term_length) -> {
      let within_bounds =
        and {
          new_term_length >= config.min_term_length,
          new_term_length <= config.max_term_length,
        }
      let max_delta = config.current_term_length / 2
      let actual_delta =
        if new_term_length > config.current_term_length {
          new_term_length - config.current_term_length
        } else {
          config.current_term_length - new_term_length
        }
      let gradual_change = actual_delta <= max_delta
      and {
        within_bounds?,
        gradual_change?,
      }
    }
    None -> True
  }
}

validator constitution_guard {
  propose(
    config: ConstitutionConfig,
    proposal: ProposalProcedure,
    self: Transaction,
  ) -> Bool {
    when proposal.governance_action is {
      ProtocolParameters { proposed_parameters, .. } ->
        validate_term_length_in_proposal(proposed_parameters, config)
      _ -> True
    }
  }

  else(_) {
    fail
  }
}

use cardano/assets
use cardano/transaction.{OutputReference, Redeemer, Transaction}
use aiken/collection/list

// ============================================================
// TIPOS
// ============================================================

pub type ComputationRedeemer<a, b> {
  input_arg: a,
  result: b,
}

pub type ValidationRedeemer<a> {
  input_arg: a,
}

// Redeemer principal del validador
pub type RewardsRedeemer {
  // Caso 1: Cálculo pesado (raíz cuadrada) hecho off-chain
  ComputeReward(ComputationRedeemer<Int, Int>)
  // Caso 2: Validación simple hecha completamente on-chain
  ClaimReward(ValidationRedeemer<ByteArray>)
}

// ============================================================
// FUNCIONES AUXILIARES
// ============================================================

/// Verificar que `result` es la raíz cuadrada entera de `input_arg`.
/// Esto es MUCHO más barato que calcularla on-chain.
fn verify_sqrt(input: Int, claimed_result: Int) -> Bool {
  let squared = claimed_result * claimed_result
  let next_squared = (claimed_result + 1) * (claimed_result + 1)
  // claimed_result² <= input < (claimed_result + 1)²
  squared <= input && input < next_squared && claimed_result >= 0
}

/// Validación simple: solo verificar que el beneficiario firmó.
fn verify_signature(tx: Transaction, beneficiary_pkh: ByteArray) -> Bool {
  list.has(tx.extra_signatories, beneficiary_pkh)
}

// ============================================================
// VALIDADOR
// ============================================================

validator rewards_validator {
  spend(
    _datum: Option<Data>,
    redeemer: RewardsRedeemer,
    _oref: OutputReference,
    tx: Transaction,
  ) {
    when redeemer is {
      // ─────────────────────────────────────────────────
      // CASO 1: ComputationRedeemer
      // La raíz cuadrada se calculó OFF-CHAIN.
      // On-chain SOLO VERIFICAMOS que el resultado sea correcto.
      //
      // ¿POR QUÉ? Calcular sqrt on-chain es O(n) iteraciones,
      // pero verificar que r² <= n < (r+1)² es O(1).
      // ─────────────────────────────────────────────────
      ComputeReward(computation) -> {
        let input = computation.input_arg
        let claimed_sqrt = computation.result

        // Verificación barata: ¿el resultado pre-computado es correcto?
        let sqrt_is_valid = verify_sqrt(input, claimed_sqrt)

        // Lógica de negocio: recompensa = sqrt(staked_amount)
        // Verificar que la salida paga exactamente esa cantidad
        let reward_amount = claimed_sqrt

        let pays_correct_reward =
          list.any(
            tx.outputs,
            fn(output) {
              assets.lovelace_of(output.value) >= reward_amount * 1_000_000
            },
          )

        sqrt_is_valid && pays_correct_reward
      }

      // ─────────────────────────────────────────────────
      // CASO 2: ValidationRedeemer
      // Todo se valida ON-CHAIN. No hay resultado pre-computado.
      // Solo pasamos el argumento de entrada (la clave del beneficiario)
      // y el validador ejecuta toda la lógica internamente.
      //
      // ¿POR QUÉ? La operación es barata (verificar una firma),
      // no necesitamos optimización off-chain.
      // ─────────────────────────────────────────────────
      ClaimReward(validation) -> {
        let beneficiary_pkh = validation.input_arg

        // Validación completa on-chain: simplemente verificar firma
        verify_signature(tx, beneficiary_pkh)
      }

      // Catch-all requerido por Aiken v3
      else(_) -> fail
    }
  }

  else(_) {
    fail
  }
}

