/// Returns the number of distinct asset names under `policy_id`
/// whose quantity is strictly positive.
fn count_positive_tokens(val: assets.Value, policy_id: ByteArray) -> Int {
  let tok: Dict<ByteArray, Int> = assets.tokens(val, policy_id)
  // Convert the dict values to a list and count those > 0
  tok
    |> dict.values
    |> list.count(fn(qty) { qty > 0 })
