use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/collection/dict

validator music_token_policy(authorized_composer: VerificationKeyHash) {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    let signed_by_composer =
      list.has(self.extra_signatories, authorized_composer)

    let minted_tokens =
      assets.tokens(self.mint, policy_id)

    let total_minted =
      assets.reduce(
        assets.from_asset_list([Pair(policy_id, assets.tokens(self.mint, policy_id) |> aiken/collection/dict.to_pairs)]),
        0,
        fn(_pid, _an, qty, acc) { acc + qty },
      )

    let exactly_one =
      assets.flatten(self.mint)
        |> list.filter(fn(triple) {
            let (pid, _an, _qty) = triple
            pid == policy_id
          })
        |> list.length() == 1

    signed_by_composer && exactly_one
  }

  else(_) {
    False
  }
}

