validator price_feed_multiplier {
  spend(
    datum: Option<SpendDatum>,
    redeemer: Int,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(feed_input) =
      find_input(self.reference_inputs, d.feed_ref)
    expect InlineDatum(raw) = feed_input.output.datum
    expect feed: PriceFeedDatum = raw
    let expected_amount = feed.unit_price * redeemer
    let own_input_value =
      when find_input(self.inputs, _own_ref) is {
        Some(i) -> assets.lovelace_of(i.output.value)
        None -> 0
      }
    own_input_value >= expected_amount
  }
}

