pub type BondingCurveRedeemer {
  payment_utxo: OutputReference,
  mint_amount: Int,
  current_supply: Int,
  token_name: ByteArray,
}

validator bonding_curve_policy(treasury_address: ByteArray, base_price: Int) {
  mint(redeemer: BondingCurveRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let price_per_token = base_price + redeemer.current_supply * base_price / 100
    let total_cost = price_per_token * redeemer.mint_amount
    let payment_made =
      list.any(
        self.outputs,
        fn(output) {
          output.address.payment_credential == cardano/address.Script(treasury_address) && assets.lovelace_of(
            output.value,
          ) >= total_cost
        },
      )
    let consumed_utxo =
      list.any(
        self.inputs,
        fn(input) { input.output_reference == redeemer.payment_utxo },
      )
    let correct_mint =
      assets.quantity_of(self.mint, policy_id, redeemer.token_name) == redeemer.mint_amount
    let positive_amount = redeemer.mint_amount > 0
    consumed_utxo && correct_mint && positive_amount && payment_made
  }
}

