}

validator bridge_token_policy(min_validators: Int) {
  mint(redeemer: BridgeRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let validator_signatures =
      list.count(
        redeemer.validator_keys,
        fn(vk) { list.has(self.extra_signatories, vk) },
      )
    let enough_validators = validator_signatures >= min_validators
    let positive_amount = redeemer.bridge_amount > 0
    let correct_mint =
      assets.quantity_of(self.mint, policy_id, redeemer.token_name) == redeemer.bridge_amount
    let valid_proof =
      builtin.length_of_bytearray(redeemer.bridge_proof_hash) == 32
    enough_validators && positive_amount && correct_mint && valid_proof
  }
}

