use aiken/primitive/bytearray
use cardano/transaction.{Transaction, OutputReference}
use aiken/fuzz

/// Check if user_permissions has all bits in required_mask set.
/// We AND them together; if result equals required_mask, all bits are present.
fn has_all_permissions(user_permissions: ByteArray, required_mask: ByteArray) -> Bool {
  let result = bytearray.and_bytes(user_permissions, required_mask, False)
  result == required_mask
}

/// Count how many permission bytes are fully granted (equal to 0xff after AND)
fn count_full_bytes(user_permissions: ByteArray, required_mask: ByteArray) -> Int {
  let result = bytearray.and_bytes(user_permissions, required_mask, False)
  let len = bytearray.length(result)
  do_count_full(result, 0, len, 0)
}

fn do_count_full(bs: ByteArray, idx: Int, len: Int, acc: Int) -> Int {
  if idx >= len {
    acc
  } else {
    let byte = bytearray.at(bs, idx)
    if byte == 255 {
      do_count_full(bs, idx + 1, len, acc + 1)
    } else {
      do_count_full(bs, idx + 1, len, acc)
    }
  }
}

validator permission_check {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let user = #"ff0f"
    let required = #"f00f"
    has_all_permissions(user, required)
  }
}

test has_all_permissions_full_match() {
  has_all_permissions(#"ff", #"0f") == True
}

test has_all_permissions_partial_fail() {
  has_all_permissions(#"0f", #"f0") == False
}

test has_all_permissions_exact() {
  has_all_permissions(#"ab", #"ab") == True
}

test count_full_bytes_two_full() {
  count_full_bytes(#"ffff", #"ffff") == 2
}

test count_full_bytes_one_partial() {
  count_full_bytes(#"ff0f", #"ffff") == 1
}

test prop_count_full_bytes_non_negative(vals via fuzz.both(fuzz.bytearray(), fuzz.bytearray())) {
  let (user_permissions, required_mask) = vals
  count_full_bytes(user_permissions, required_mask) >= 0
}

test prop_do_count_full_non_negative(vals via fuzz.tuple4(fuzz.bytearray_between(0, 32), fuzz.int_at_least(0), fuzz.int_between(0, 10), fuzz.int_at_least(0))) {
  let (bs, idx, len, acc) = vals
  do_count_full(bs, idx, len, acc) >= 0
}
